   182→        "tool_use" | "task_start" => {
   183→            let task_id = value.get("bead_id")
   184→                .or_else(|| value.get("task_id"))
   185→                .and_then(|v| v.as_str())
   186→                .unwrap_or("unknown")
   187→                .to_string();
   188→
   189→            let model = value.get("model")
   190→                .and_then(|v| v.as_str())
   191→                .unwrap_or("unknown")
   192→                .to_string();
   193→
   194→            Some(TaskEvent::Started {
   195→                task_id,
   196→                worker_id: worker_id.to_string(),
   197→                model,
   198→            })
   199→        }
   200→
   201→        // Task completion event - result type with success/failure
   202→        "result" => {
   203→            let task_id = value.get("bead_id")
   204→                .and_then(|v| v.as_str())
   205→                .unwrap_or("unknown")
   206→                .to_string();
   207→
   208→            // Check for success/failure
   209→            let subtype = value.get("subtype")
   210→                .and_then(|v| v.as_str())
   211→                .unwrap_or("");
   212→
   213→            let success = subtype == "success";
   214→
   215→            // Extract duration if available
   216→            let duration_ms = value.get("duration_ms")
   217→                .or_else(|| value.get("duration_api_ms"))
   218→                .and_then(|v| v.as_u64())
   219→                .unwrap_or(0);
   220→
   221→            // Extract usage data
   222→            let usage = value.get("usage");
   223→            let (input_tokens, output_tokens) = if let Some(u) = usage {
   224→                let input = u.get("input_tokens").and_then(|v| v.as_i64()).unwrap_or(0);
   225→                let output = u.get("output_tokens").and_then(|v| v.as_i64()).unwrap_or(0);
   226→                (input, output)
   227→            } else {
   228→                (0, 0)
   229→            };
   230→
   231→            // Extract or calculate cost
