   240→                        Some(cost)
   241→                    } else {
   242→                        None
   243→                    }
   244→                })
   245→                .unwrap_or(0.0);
   246→
   247→            if success {
   248→                Some(TaskEvent::Completed {
   249→                    task_id,
   250→                    worker_id: worker_id.to_string(),
   251→                    success: true,
   252→                    duration_ms,
   253→                    input_tokens,
   254→                    output_tokens,
   255→                    cost_usd,
