   391→                        events.push(LogWatcherEvent::FileDiscovered { path, worker_id });
   392→                    }
   393→                }
   394→            }
   395→        }
   396→
   397→        // Collect paths to process (avoid borrow issues)
   398→        let paths: Vec<PathBuf> = self.tracked_files.keys().cloned().collect();
   399→
   400→        // Read new content from tracked files
   401→        for path in paths {
   402→            if let Some(tracked) = self.tracked_files.get_mut(&path) {
   403→                match Self::read_new_content_static(&path, tracked, &self.parser) {
   404→                    Ok(calls) => {
   405→                        for call in calls {
   406→                            events.push(LogWatcherEvent::ApiCallParsed { call });
   407→                        }
   408→                    }
   409→                    Err(e) => {
   410→                        trace!("Error reading log file {:?}: {}", path, e);
   411→                    }
   412→                }
   413→            }
   414→        }
   415→
   416→        events
   417→    }
   418→
   419→    /// Static version of read_new_content to avoid borrow checker issues.
   420→    fn read_new_content_static(
   421→        path: &Path,
   422→        tracked: &mut TrackedFile,
   423→        parser: &LogParser,
   424→    ) -> Result<Vec<ApiCall>, LogWatcherError> {
   425→        let mut file = File::open(path).map_err(|e| LogWatcherError::ReadError {
   426→            path: path.to_path_buf(),
   427→            source: e,
   428→        })?;
   429→
   430→        // Check for rotation (inode change on Unix)
   431→        #[cfg(unix)]
   432→        {
   433→            use std::os::unix::fs::MetadataExt;
   434→            let metadata = file.metadata().map_err(|e| LogWatcherError::ReadError {
   435→                path: path.to_path_buf(),
   436→                source: e,
   437→            })?;
   438→            let current_inode = metadata.ino();
   439→
   440→            if let Some(prev_inode) = tracked.inode {
   441→                if current_inode != prev_inode {
   442→                    // File rotated - reset position
   443→                    debug!("Log file rotated: {:?}", path);
   444→                    tracked.position = 0;
   445→                }
   446→            }
   447→            tracked.inode = Some(current_inode);
   448→        }
   449→
   450→        // Seek to last position
   451→        file.seek(SeekFrom::Start(tracked.position))
   452→            .map_err(|e| LogWatcherError::ReadError {
   453→                path: path.to_path_buf(),
   454→                source: e,
   455→            })?;
   456→
   457→        let mut reader = BufReader::new(file);
   458→        let mut calls = Vec::new();
   459→
   460→        loop {
   461→            let mut line = String::new();
   462→            match reader.read_line(&mut line) {
   463→                Ok(0) => break, // EOF
   464→                Ok(_) => {
   465→                    let line = line.trim();
   466→                    if line.is_empty() || !line.starts_with('{') {
   467→                        continue;
   468→                    }
   469→
   470→                    // Parse the line for API usage
   471→                    match parser.parse_line(line, &tracked.worker_id) {
   472→                        Ok(Some(call)) => {
   473→                            calls.push(call);
   474→                        }
   475→                        Ok(None) => {
   476→                            // Line didn't contain usage data - skip
   477→                        }
   478→                        Err(e) => {
   479→                            trace!("Failed to parse log line: {}", e);
   480→                        }
   481→                    }
   482→                }
   483→                Err(e) => {
   484→                    warn!("Error reading line from {:?}: {}", path, e);
   485→                    break;
   486→                }
   487→            }
   488→        }
   489→
   490→        // Update position
   491→        tracked.position = reader
   492→            .stream_position()
   493→            .map_err(|e| LogWatcherError::ReadError {
   494→                path: path.to_path_buf(),
   495→                source: e,
   496→            })?;
   497→
   498→        Ok(calls)
   499→    }
   500→
   501→    /// Get the log directory being watched.
   502→    pub fn log_dir(&self) -> &Path {
   503→        &self.log_dir
   504→    }
   505→
   506→    /// Get the number of tracked files.
   507→    pub fn tracked_file_count(&self) -> usize {
   508→        self.tracked_files.len()
   509→    }
   510→}
   511→
   512→/// Simple file tailer for reading new lines from log files.
   513→pub struct FileTailer {
   514→    /// Event sender
   515→    event_tx: Sender<LogWatcherEvent>,
   516→}
   517→
   518→impl FileTailer {
   519→    /// Create a new file tailer.
   520→    pub fn new(event_tx: Sender<LogWatcherEvent>) -> Self {
   521→        Self { event_tx }
   522→    }
   523→
   524→    /// Tail a file, sending events for new lines.
   525→    pub fn tail_file(&self, path: &Path, position: &mut u64, worker_id: &str) {
   526→        let file = match File::open(path) {
   527→            Ok(f) => f,
   528→            Err(_) => return,
   529→        };
   530→
   531→        let mut reader = BufReader::new(file);
   532→
   533→        // Seek to position
   534→        if reader.seek(SeekFrom::Start(*position)).is_err() {
   535→            return;
   536→        }
   537→
   538→        let parser = LogParser::new();
   539→
   540→        loop {
   541→            let mut line = String::new();
   542→            match reader.read_line(&mut line) {
   543→                Ok(0) => break,
   544→                Ok(_) => {
   545→                    let line = line.trim();
   546→                    if line.is_empty() || !line.starts_with('{') {
   547→                        continue;
   548→                    }
   549→
   550→                    if let Ok(Some(call)) = parser.parse_line(line, worker_id) {
   551→                        let _ = self.event_tx.send(LogWatcherEvent::ApiCallParsed { call });
   552→                    }
   553→                }
   554→                Err(_) => break,
   555→            }
   556→        }
   557→
   558→        // Update position
   559→        if let Ok(new_pos) = reader.stream_position() {
   560→            *position = new_pos;
   561→        }
   562→    }
   563→}
   564→
   565→/// Process a file system event.
   566→fn process_file_event(
   567→    event: &NotifyEvent,
   568→    log_dir: &Path,
   569→    tx: &Sender<LogWatcherEvent>,
   570→) -> Result<(), LogWatcherError> {
   571→    for path in &event.paths {
   572→        // Only process .log files
   573→        if path.extension().and_then(|e| e.to_str()) != Some("log") {
   574→            continue;
   575→        }
   576→
   577→        // Extract worker ID from filename
   578→        let worker_id = match path.file_stem().and_then(|s| s.to_str()) {
   579→            Some(id) => id.to_string(),
   580→            None => continue,
   581→        };
   582→
   583→        debug!("Processing log event {:?} for worker {}", event.kind, worker_id);
   584→
   585→        match event.kind {
   586→            EventKind::Create(_) => {
   587→                let _ = tx.send(LogWatcherEvent::FileDiscovered {
   588→                    path: path.clone(),
   589→                    worker_id,
   590→                });
   591→            }
   592→            EventKind::Modify(_) => {
   593→                // Modifications are handled by polling
   594→            }
   595→            EventKind::Remove(_) => {
   596→                // File removed - this could be rotation
   597→                let _ = tx.send(LogWatcherEvent::FileRotated {
   598→                    path: path.clone(),
   599→                    worker_id,
   600→                });
   601→            }
   602→            _ => {}
   603→        }
   604→    }
   605→
   606→    Ok(())
   607→}
   608→
   609→/// Real-time metrics aggregator for parsed API calls.
   610→#[derive(Debug, Default, Clone)]
   611→pub struct RealtimeMetrics {
   612→    /// Total API calls today
   613→    pub total_calls: i64,
   614→
   615→    /// Total cost today (USD)
   616→    pub total_cost: f64,
   617→
   618→    /// Total input tokens today
   619→    pub total_input_tokens: i64,
   620→
   621→    /// Total output tokens today
   622→    pub total_output_tokens: i64,
   623→
   624→    /// Calls per model
   625→    pub calls_by_model: HashMap<String, i64>,
   626→
   627→    /// Cost per model
   628→    pub cost_by_model: HashMap<String, f64>,
   629→
   630→    /// Last update timestamp
   631→    pub last_update: Option<DateTime<Utc>>,
   632→}
   633→
   634→impl RealtimeMetrics {
   635→    /// Create new empty metrics.
   636→    pub fn new() -> Self {
   637→        Self::default()
   638→    }
   639→
   640→    /// Record an API call.
   641→    pub fn record_call(&mut self, call: &ApiCall) {
   642→        self.total_calls += 1;
   643→        self.total_cost += call.cost_usd;
   644→        self.total_input_tokens += call.input_tokens;
   645→        self.total_output_tokens += call.output_tokens;
   646→
   647→        *self.calls_by_model.entry(call.model.clone()).or_insert(0) += 1;
   648→        *self.cost_by_model.entry(call.model.clone()).or_insert(0.0) += call.cost_usd;
   649→
   650→        self.last_update = Some(Utc::now());
   651→    }
   652→
   653→    /// Get average cost per call.
   654→    pub fn avg_cost_per_call(&self) -> f64 {
   655→        if self.total_calls == 0 {
   656→            0.0
   657→        } else {
   658→            self.total_cost / self.total_calls as f64
   659→        }
   660→    }
   661→
   662→    /// Get total tokens.
   663→    pub fn total_tokens(&self) -> i64 {
   664→        self.total_input_tokens + self.total_output_tokens
   665→    }
   666→
   667→    /// Clear all metrics.
   668→    pub fn clear(&mut self) {
   669→        self.total_calls = 0;
   670→        self.total_cost = 0.0;
   671→        self.total_input_tokens = 0;
   672→        self.total_output_tokens = 0;
   673→        self.calls_by_model.clear();
   674→        self.cost_by_model.clear();
   675→        self.last_update = None;
   676→    }
   677→
   678→    /// Check if we have any data.
   679→    pub fn has_data(&self) -> bool {
   680→        self.total_calls > 0
   681→    }
   682→}
