     1→//! Status file monitoring for worker health tracking.
     2→//!
     3→//! This module provides a debounced file watcher for monitoring worker status
     4→//! files in `~/.forge/status/*.json`. It uses the notify crate to watch for
     5→//! file system events and updates worker state accordingly.
     6→//!
     7→//! ## Architecture
     8→//!
     9→//! The status watcher operates as follows:
    10→//! 1. Watches `~/.forge/status/` directory for file changes
    11→//! 2. Debounces rapid file changes (10-30ms typical latency)
    12→//! 3. Parses status JSON files when they change
    13→//! 4. Sends updates via a channel to the main TUI event loop
    14→//!
    15→//! ## Status File Format
    16→//!
    17→//! Workers write JSON status files with the following format:
    18→//! ```json
    19→//! {
    20→//!   "worker_id": "sonnet-alpha",
    21→//!   "status": "active",
    22→//!   "model": "claude-sonnet-4-5",
    23→//!   "workspace": "/path/to/workspace",
    24→//!   "pid": 12345,
    25→//!   "started_at": "2026-02-08T10:30:00Z",
    26→//!   "last_activity": "2026-02-08T10:35:00Z",
    27→//!   "current_task": "bd-abc",
    28→//!   "tasks_completed": 5
    29→//! }
    30→//! ```
    31→
    32→#[cfg(test)]
    33→use std::sync::Mutex;
    34→
    35→/// Global mutex to serialize StatusWatcher creation in tests.
    36→/// This prevents exhausting inotify limits when many tests run in parallel.
    37→#[cfg(test)]
    38→static TEST_WATCHER_MUTEX: Mutex<()> = Mutex::new(());
    39→
    40→use std::collections::HashMap;
    41→use std::path::{Path, PathBuf};
    42→use std::sync::mpsc::{self, Receiver, Sender};
    43→use std::time::Duration;
    44→
    45→use chrono::{DateTime, Utc};
    46→use notify::RecursiveMode;
    47→use notify_debouncer_full::{
    48→    DebounceEventResult, DebouncedEvent, Debouncer, RecommendedCache, new_debouncer,
    49→};
    50→use serde::{Deserialize, Serialize};
    51→use thiserror::Error;
    52→use tracing::{debug, error, info, warn};
    53→
    54→use forge_core::types::WorkerStatus;
    55→
    56→/// Default debounce timeout in milliseconds.
    57→const DEFAULT_DEBOUNCE_MS: u64 = 50;
    58→
    59→/// Errors that can occur during status monitoring.
    60→#[derive(Error, Debug)]
    61→pub enum StatusWatcherError {
    62→    /// Failed to initialize the file watcher
    63→    #[error("Failed to initialize file watcher: {0}")]
    64→    WatcherInit(#[from] notify::Error),
    65→
    66→    /// Failed to read status file
    67→    #[error("Failed to read status file {path}: {source}")]
    68→    ReadFile {
    69→        path: PathBuf,
    70→        #[source]
    71→        source: std::io::Error,
    72→    },
    73→
    74→    /// Failed to parse status file JSON
    75→    #[error("Failed to parse status file {path}: {source}")]
    76→    ParseJson {
    77→        path: PathBuf,
    78→        #[source]
    79→        source: serde_json::Error,
    80→    },
    81→
    82→    /// Status directory does not exist
    83→    #[error("Status directory does not exist: {0}")]
    84→    DirectoryNotFound(PathBuf),
    85→
    86→    /// Failed to create status directory
    87→    #[error("Failed to create status directory {path}: {source}")]
    88→    CreateDirectory {
    89→        path: PathBuf,
    90→        #[source]
    91→        source: std::io::Error,
    92→    },
    93→}
    94→
    95→/// Result type for status watcher operations.
    96→pub type StatusWatcherResult<T> = Result<T, StatusWatcherError>;
    97→
    98→/// Custom deserializer for current_task field that handles both string and object formats.
    99→///
   100→/// Accepts:
   101→/// - String: "bd-abc"
   102→/// - Object: {"bead_id": "bd-abc", "bead_title": "...", "priority": 1}
   103→fn deserialize_current_task<'de, D>(deserializer: D) -> Result<Option<String>, D::Error>
   104→where
   105→    D: serde::Deserializer<'de>,
   106→{
   107→    use serde::de::{self, Deserialize};
   108→    use serde_json::Value;
   109→
   110→    let value = Value::deserialize(deserializer)?;
   111→
   112→    match value {
   113→        Value::Null => Ok(None),
   114→        Value::String(s) => Ok(Some(s)),
   115→        Value::Object(map) => {
   116→            // Extract bead_id from object format
   117→            if let Some(Value::String(bead_id)) = map.get("bead_id") {
   118→                Ok(Some(bead_id.clone()))
   119→            } else {
   120→                Err(de::Error::custom(
   121→                    "current_task object must have bead_id field",
   122→                ))
   123→            }
   124→        }
   125→        _ => Err(de::Error::custom("current_task must be a string or object")),
   126→    }
   127→}
   128→
   129→/// Worker status as read from a status file.
   130→///
   131→/// This struct represents the JSON format of worker status files.
   132→#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
   133→pub struct WorkerStatusFile {
   134→    /// Unique worker identifier (matches filename without .json)
   135→    pub worker_id: String,
   136→
   137→    /// Current worker status
   138→    #[serde(default)]
   139→    pub status: WorkerStatus,
   140→
   141→    /// Model being used by this worker
   142→    #[serde(default)]
   143→    pub model: String,
   144→
   145→    /// Working directory for the worker
   146→    #[serde(default)]
   147→    pub workspace: String,
   148→
   149→    /// Process ID of the worker
   150→    #[serde(default)]
   151→    pub pid: Option<u32>,
   152→
   153→    /// When the worker was started
   154→    #[serde(default)]
   155→    pub started_at: Option<DateTime<Utc>>,
   156→
   157→    /// Last activity timestamp
   158→    #[serde(default)]
   159→    pub last_activity: Option<DateTime<Utc>>,
   160→
   161→    /// Current task/bead being worked on (handles both string and object formats)
   162→    #[serde(default, deserialize_with = "deserialize_current_task")]
   163→    pub current_task: Option<String>,
   164→
   165→    /// Number of tasks completed
   166→    #[serde(default)]
   167→    pub tasks_completed: u32,
   168→
   169→    /// Optional container ID (for containerized workers)
   170→    #[serde(default)]
   171→    pub container_id: Option<String>,
   172→}
   173→
   174→impl WorkerStatusFile {
   175→    /// Parse a status file from JSON content.
   176→    pub fn from_json(content: &str, path: &Path) -> StatusWatcherResult<Self> {
   177→        serde_json::from_str(content).map_err(|e| StatusWatcherError::ParseJson {
   178→            path: path.to_path_buf(),
   179→            source: e,
   180→        })
   181→    }
   182→
   183→    /// Read and parse a status file from disk.
   184→    pub fn from_file(path: &Path) -> StatusWatcherResult<Self> {
   185→        let content = std::fs::read_to_string(path).map_err(|e| StatusWatcherError::ReadFile {
   186→            path: path.to_path_buf(),
   187→            source: e,
   188→        })?;
   189→        Self::from_json(&content, path)
   190→    }
   191→
   192→    /// Check if the worker is considered healthy.
   193→    pub fn is_healthy(&self) -> bool {
   194→        self.status.is_healthy()
   195→    }
   196→}
   197→
   198→/// Events sent by the status watcher to the TUI.
   199→#[derive(Debug, Clone)]
   200→pub enum StatusEvent {
   201→    /// A worker status was created or updated
   202→    WorkerUpdated {
   203→        worker_id: String,
   204→        status: WorkerStatusFile,
   205→    },
   206→
   207→    /// A worker status file was deleted
   208→    WorkerRemoved { worker_id: String },
   209→
   210→    /// Initial scan completed with all current workers
   211→    InitialScanComplete {
   212→        workers: HashMap<String, WorkerStatusFile>,
   213→    },
   214→
   215→    /// An error occurred while processing a status file
   216→    Error { path: PathBuf, error: String },
   217→}
   218→
   219→/// Configuration for the status watcher.
   220→#[derive(Debug, Clone)]
   221→pub struct StatusWatcherConfig {
   222→    /// Path to the status directory (default: ~/.forge/status)
   223→    pub status_dir: PathBuf,
   224→
   225→    /// Debounce timeout in milliseconds
   226→    pub debounce_ms: u64,
   227→
   228→    /// Whether to create the status directory if it doesn't exist
   229→    pub create_dir_if_missing: bool,
   230→}
   231→
   232→impl Default for StatusWatcherConfig {
   233→    fn default() -> Self {
   234→        Self {
   235→            status_dir: Self::default_status_dir(),
   236→            debounce_ms: DEFAULT_DEBOUNCE_MS,
   237→            create_dir_if_missing: true,
   238→        }
   239→    }
   240→}
   241→
   242→impl StatusWatcherConfig {
   243→    /// Get the default status directory path (~/.forge/status).
   244→    pub fn default_status_dir() -> PathBuf {
   245→        dirs::home_dir()
   246→            .unwrap_or_else(|| PathBuf::from("."))
   247→            .join(".forge")
   248→            .join("status")
   249→    }
   250→
   251→    /// Set a custom status directory.
   252→    pub fn with_status_dir(mut self, dir: impl Into<PathBuf>) -> Self {
   253→        self.status_dir = dir.into();
   254→        self
   255→    }
   256→
   257→    /// Set the debounce timeout.
   258→    pub fn with_debounce_ms(mut self, ms: u64) -> Self {
   259→        self.debounce_ms = ms;
   260→        self
   261→    }
   262→}
   263→
   264→/// Watcher for worker status files.
   265→///
   266→/// This struct manages the file system watcher and provides a channel
   267→/// for receiving status updates.
   268→pub struct StatusWatcher {
   269→    /// Configuration for the watcher
   270→    config: StatusWatcherConfig,
   271→
   272→    /// The debounced file watcher
   273→    _debouncer: Option<Debouncer<notify::RecommendedWatcher, RecommendedCache>>,
   274→
   275→    /// Receiver for status events
   276→    event_rx: Receiver<StatusEvent>,
   277→
   278→    /// Current worker states
   279→    workers: HashMap<String, WorkerStatusFile>,
   280→}
   281→
   282→impl Drop for StatusWatcher {
   283→    fn drop(&mut self) {
   284→        self.stop();
   285→    }
   286→}
   287→
   288→impl StatusWatcher {
   289→    /// Create a new status watcher with the given configuration.
   290→    pub fn new(config: StatusWatcherConfig) -> StatusWatcherResult<Self> {
   291→        // In test mode, acquire a global mutex to serialize StatusWatcher creation.
   292→        // This prevents exhausting inotify limits when many tests run in parallel.
   293→        #[cfg(test)]
   294→        let _guard = TEST_WATCHER_MUTEX.lock().unwrap();
   295→
   296→        // Ensure status directory exists
   297→        if !config.status_dir.exists() {
   298→            if config.create_dir_if_missing {
   299→                std::fs::create_dir_all(&config.status_dir).map_err(|e| {
   300→                    StatusWatcherError::CreateDirectory {
   301→                        path: config.status_dir.clone(),
   302→                        source: e,
   303→                    }
   304→                })?;
   305→                info!(path = ?config.status_dir, "Created status directory");
   306→            } else {
   307→                return Err(StatusWatcherError::DirectoryNotFound(
   308→                    config.status_dir.clone(),
   309→                ));
   310→            }
   311→        }
   312→
   313→        // Create channel for status events
   314→        let (event_tx, event_rx) = mpsc::channel();
   315→
   316→        // Create debounced watcher
   317→        let status_dir = config.status_dir.clone();
   318→        let tx_clone = event_tx.clone();
   319→
   320→        let debouncer = new_debouncer(
   321→            Duration::from_millis(config.debounce_ms),
   322→            None,
   323→            move |result: DebounceEventResult| {
   324→                Self::handle_debounced_events(result, &status_dir, &tx_clone);
   325→            },
   326→        )?;
   327→
   328→        let mut watcher = Self {
   329→            config,
   330→            _debouncer: Some(debouncer),
   331→            event_rx,
   332→            workers: HashMap::new(),
   333→        };
   334→
   335→        // Start watching the directory
   336→        watcher.start_watching()?;
   337→
   338→        // Perform initial scan
   339→        watcher.initial_scan(event_tx)?;
   340→
   341→        Ok(watcher)
   342→    }
   343→
   344→    /// Create a new status watcher with default configuration.
   345→    pub fn new_default() -> StatusWatcherResult<Self> {
   346→        Self::new(StatusWatcherConfig::default())
   347→    }
   348→
   349→    /// Stop watching and release resources.
   350→    ///
   351→    /// This method should be called when the watcher is no longer needed
   352→    /// to ensure the inotify instance is released immediately.
   353→    pub fn stop(&mut self) {
   354→        // The debouncer's stop method takes ownership, so we need to take it
   355→        if let Some(debouncer) = self._debouncer.take() {
   356→            debouncer.stop();
   357→            debug!("Status watcher stopped");
   358→        }
   359→    }
   360→
   361→    /// Start watching the status directory.
   362→    fn start_watching(&mut self) -> StatusWatcherResult<()> {
   363→        if let Some(ref mut debouncer) = self._debouncer {
   364→            debouncer.watch(&self.config.status_dir, RecursiveMode::NonRecursive)?;
   365→            info!(path = ?self.config.status_dir, "Started watching status directory");
   366→        }
   367→        Ok(())
   368→    }
   369→
   370→    /// Perform initial scan of existing status files.
   371→    fn initial_scan(&mut self, event_tx: Sender<StatusEvent>) -> StatusWatcherResult<()> {
   372→        let mut workers = HashMap::new();
   373→
   374→        if let Ok(entries) = std::fs::read_dir(&self.config.status_dir) {
   375→            for entry in entries.flatten() {
   376→                let path = entry.path();
   377→                if path.extension().is_some_and(|e| e == "json") {
   378→                    match WorkerStatusFile::from_file(&path) {
   379→                        Ok(status) => {
   380→                            debug!(worker_id = %status.worker_id, "Found existing worker status");
   381→                            workers.insert(status.worker_id.clone(), status);
   382→                        }
   383→                        Err(e) => {
   384→                            warn!(path = ?path, error = %e, "Failed to parse existing status file");
   385→                        }
   386→                    }
   387→                }
   388→            }
   389→        }
   390→
   391→        self.workers = workers.clone();
   392→
   393→        // Send initial scan complete event
   394→        let _ = event_tx.send(StatusEvent::InitialScanComplete { workers });
   395→
   396→        Ok(())
   397→    }
   398→
   399→    /// Handle debounced file system events.
   400→    fn handle_debounced_events(
   401→        result: DebounceEventResult,
   402→        status_dir: &Path,
   403→        event_tx: &Sender<StatusEvent>,
   404→    ) {
   405→        match result {
   406→            Ok(events) => {
   407→                for event in events {
   408→                    Self::process_event(event, status_dir, event_tx);
   409→                }
   410→            }
   411→            Err(errors) => {
   412→                for error in errors {
   413→                    error!(error = %error, "File watcher error");
   414→                }
   415→            }
   416→        }
   417→    }
   418→
   419→    /// Process a single debounced event.
   420→    fn process_event(event: DebouncedEvent, status_dir: &Path, event_tx: &Sender<StatusEvent>) {
   421→        use notify::EventKind;
   422→
   423→        for path in &event.paths {
   424→            // Only process .json files in the status directory
   425→            if !path.extension().is_some_and(|e| e == "json") {
   426→                continue;
   427→            }
   428→
   429→            // Ensure the file is in the status directory
   430→            if path.parent() != Some(status_dir) {
   431→                continue;
   432→            }
   433→
   434→            // Extract worker ID from filename
   435→            let worker_id = match path.file_stem().and_then(|s| s.to_str()) {
   436→                Some(id) => id.to_string(),
   437→                None => continue,
   438→            };
   439→
   440→            match event.kind {
   441→                EventKind::Create(_) | EventKind::Modify(_) => {
   442→                    // File created or modified - read and parse
   443→                    match WorkerStatusFile::from_file(path) {
   444→                        Ok(status) => {
   445→                            debug!(worker_id = %status.worker_id, "Worker status updated");
   446→                            let _ = event_tx.send(StatusEvent::WorkerUpdated {
   447→                                worker_id: status.worker_id.clone(),
   448→                                status,
   449→                            });
   450→                        }
   451→                        Err(e) => {
   452→                            warn!(path = ?path, error = %e, "Failed to parse status file");
   453→                            let _ = event_tx.send(StatusEvent::Error {
   454→                                path: path.clone(),
   455→                                error: e.to_string(),
   456→                            });
   457→                        }
   458→                    }
   459→                }
   460→                EventKind::Remove(_) => {
   461→                    // File deleted
   462→                    debug!(worker_id = %worker_id, "Worker status file removed");
   463→                    let _ = event_tx.send(StatusEvent::WorkerRemoved { worker_id });
   464→                }
   465→                _ => {
   466→                    // Other events (access, etc.) - ignore
   467→                }
   468→            }
   469→        }
   470→    }
   471→
   472→    /// Try to receive a status event without blocking.
   473→    pub fn try_recv(&mut self) -> Option<StatusEvent> {
   474→        match self.event_rx.try_recv() {
   475→            Ok(event) => {
   476→                self.apply_event(&event);
   477→                Some(event)
   478→            }
   479→            Err(_) => None,
   480→        }
   481→    }
   482→
   483→    /// Receive a status event, blocking until one is available.
   484→    pub fn recv(&mut self) -> Option<StatusEvent> {
   485→        match self.event_rx.recv() {
   486→            Ok(event) => {
   487→                self.apply_event(&event);
   488→                Some(event)
   489→            }
   490→            Err(_) => None,
   491→        }
   492→    }
   493→
   494→    /// Receive a status event with a timeout.
   495→    pub fn recv_timeout(&mut self, timeout: Duration) -> Option<StatusEvent> {
   496→        match self.event_rx.recv_timeout(timeout) {
   497→            Ok(event) => {
   498→                self.apply_event(&event);
   499→                Some(event)
   500→            }
   501→            Err(_) => None,
   502→        }
   503→    }
   504→
   505→    /// Apply an event to the internal worker state.
   506→    fn apply_event(&mut self, event: &StatusEvent) {
   507→        match event {
   508→            StatusEvent::WorkerUpdated { worker_id, status } => {
   509→                self.workers.insert(worker_id.clone(), status.clone());
   510→            }
   511→            StatusEvent::WorkerRemoved { worker_id } => {
   512→                self.workers.remove(worker_id);
   513→            }
   514→            StatusEvent::InitialScanComplete { workers } => {
   515→                self.workers = workers.clone();
   516→            }
   517→            StatusEvent::Error { .. } => {
   518→                // Errors don't change state
   519→            }
   520→        }
   521→    }
   522→
   523→    /// Get the current worker states.
   524→    pub fn workers(&self) -> &HashMap<String, WorkerStatusFile> {
   525→        &self.workers
   526→    }
   527→
   528→    /// Get a specific worker's status.
   529→    pub fn get_worker(&self, worker_id: &str) -> Option<&WorkerStatusFile> {
   530→        self.workers.get(worker_id)
   531→    }
   532→
   533→    /// Get the count of workers by status.
   534→    pub fn worker_counts(&self) -> WorkerCounts {
   535→        let mut counts = WorkerCounts::default();
   536→        for worker in self.workers.values() {
   537→            match worker.status {
   538→                WorkerStatus::Active => counts.active += 1,
   539→                WorkerStatus::Idle => counts.idle += 1,
   540→                WorkerStatus::Failed => counts.failed += 1,
   541→                WorkerStatus::Stopped => counts.stopped += 1,
   542→                WorkerStatus::Error => counts.error += 1,
   543→                WorkerStatus::Starting => counts.starting += 1,
   544→                WorkerStatus::Paused => counts.paused += 1,
   545→            }
   546→        }
   547→        counts.total = self.workers.len();
   548→        counts
   549→    }
   550→
   551→    /// Get list of healthy workers.
   552→    pub fn healthy_workers(&self) -> Vec<&WorkerStatusFile> {
   553→        self.workers.values().filter(|w| w.is_healthy()).collect()
   554→    }
   555→
   556→    /// Get list of unhealthy workers.
   557→    pub fn unhealthy_workers(&self) -> Vec<&WorkerStatusFile> {
   558→        self.workers.values().filter(|w| !w.is_healthy()).collect()
   559→    }
   560→}
   561→
   562→/// Summary counts of workers by status.
   563→#[derive(Debug, Default, Clone, PartialEq)]
   564→pub struct WorkerCounts {
   565→    /// Total number of workers
   566→    pub total: usize,
   567→    /// Number of active workers
   568→    pub active: usize,
   569→    /// Number of idle workers
   570→    pub idle: usize,
   571→    /// Number of failed workers
   572→    pub failed: usize,
   573→    /// Number of stopped workers
   574→    pub stopped: usize,
   575→    /// Number of workers in error state
   576→    pub error: usize,
   577→    /// Number of workers starting up
   578→    pub starting: usize,
   579→    /// Number of paused workers
   580→    pub paused: usize,
   581→}
   582→
   583→impl WorkerCounts {
   584→    /// Get the number of healthy workers (active + idle + starting).
   585→    pub fn healthy(&self) -> usize {
   586→        self.active + self.idle + self.starting
   587→    }
   588→
   589→    /// Get the number of unhealthy workers (failed + stopped + error).
   590→    pub fn unhealthy(&self) -> usize {
   591→        self.failed + self.stopped + self.error
   592→    }
   593→}
   594→
   595→/// Get the home directory path for the dirs crate compatibility.
   596→mod dirs {
   597→    use std::path::PathBuf;
   598→
   599→    pub fn home_dir() -> Option<PathBuf> {
   600→        std::env::var_os("HOME").map(PathBuf::from)
   601→    }
   602→}
