   883→    /// Test that creating a new status file triggers a WorkerUpdated event.
   884→    #[test]
   885→    #[serial(file_watcher)]
   886→    fn test_file_creation_triggers_update_event() {
   887→        let temp_dir = TempDir::new().unwrap();
   888→        let status_dir = temp_dir.path().join("status");
   889→        fs::create_dir_all(&status_dir).unwrap();
   890→
   891→        // Create watcher with short debounce for faster tests
   892→        let config = StatusWatcherConfig::default()
   893→            .with_status_dir(&status_dir)
   894→            .with_debounce_ms(10);
   895→        let mut watcher = StatusWatcher::new(config).unwrap();
   896→
   897→        // Receive initial scan event (should be empty)
   898→        let initial_event = watcher.recv_timeout(Duration::from_millis(100));
   899→        assert!(matches!(
   900→            initial_event,
   901→            Some(StatusEvent::InitialScanComplete { workers }) if workers.is_empty()
   902→        ));
   903→
   904→        // Create a new status file after the watcher is running
   905→        create_test_status_file(&status_dir, "new-worker-1", "active");
   906→
   907→        // Wait for the file system event with enough time for debounce
   908→        std::thread::sleep(Duration::from_millis(100));
   909→
   910→        // Try to receive the update event
   911→        let event = watcher.recv_timeout(Duration::from_millis(500));
   912→
   913→        // Verify we got a WorkerUpdated event
   914→        match event {
   915→            Some(StatusEvent::WorkerUpdated { worker_id, status }) => {
   916→                assert_eq!(worker_id, "new-worker-1");
   917→                assert_eq!(status.status, WorkerStatus::Active);
   918→                assert_eq!(status.model, "test-model");
   919→            }
   920→            other => {
   921→                // Also accept if the watcher detected it via internal state
   922→                if watcher.get_worker("new-worker-1").is_some() {
   923→                    let w = watcher.get_worker("new-worker-1").unwrap();
   924→                    assert_eq!(w.status, WorkerStatus::Active);
   925→                } else {
   926→                    panic!("Expected WorkerUpdated event, got: {:?}", other);
   927→                }
   928→            }
   929→        }
   930→    }
