   949→        // Verify initial state
   950→        assert_eq!(watcher.workers().len(), 1);
   951→        assert_eq!(
   952→            watcher.get_worker("worker-mod").unwrap().status,
   953→            WorkerStatus::Idle
   954→        );
   955→
   956→        // Receive initial scan event
   957→        let _ = watcher.recv_timeout(Duration::from_millis(100));
   958→
   959→        // Modify the file to change status to active
   960→        let new_content = r#"{
   961→            "worker_id": "worker-mod",
   962→            "status": "active",
   963→            "model": "test-model-updated",
   964→            "workspace": "/test/workspace",
   965→            "pid": 12345,
   966→            "tasks_completed": 10
   967→        }"#;
   968→        fs::write(&path, new_content).unwrap();
   969→
   970→        // Wait for debounce
   971→        std::thread::sleep(Duration::from_millis(100));
   972→
   973→        // Try to receive the update event
   974→        let event = watcher.recv_timeout(Duration::from_millis(500));
