   984→                if let Some(w) = watcher.get_worker("worker-mod") {
   985→                    if w.status == WorkerStatus::Active {
   986→                        // Event was applied internally
   987→                        return;
   988→                    }
   989→                }
   990→                panic!(
   991→                    "Expected WorkerUpdated event with active status, got: {:?}",
