            "worker_id": worker_id,
            "status": "active",
            "model": "sonnet",
            "workspace": "/test/workspace",
            "pid": 12345,
            "started_at": Utc::now().to_rfc3339(),
            "last_activity": Utc::now().to_rfc3339(),
            "current_task": "fg-test-task",
