   373→/// Renders a sparkline from a series of values.
   374→pub fn render_sparkline(values: &[f64], width: usize) -> String {
   375→    if values.is_empty() {
   376→        return " ".repeat(width);
   377→    }
   378→
   379→    let blocks = ['▁', '▂', '▃', '▄', '▅', '▆', '▇', '█'];
   380→    let max = values.iter().cloned().fold(0.0_f64, f64::max);
   381→    let min = values.iter().cloned().fold(f64::MAX, f64::min);
   382→    let range = max - min;
   383→
   384→    // Sample values to fit width
   385→    let step = values.len() as f64 / width as f64;
   386→    let mut result = String::with_capacity(width);
   387→
   388→    for i in 0..width {
   389→        let idx = ((i as f64) * step).min(values.len() as f64 - 1.0) as usize;
   390→        let val = values[idx];
   391→
   392→        let normalized = if range > 0.0 {
   393→            ((val - min) / range).clamp(0.0, 1.0)
   394→        } else {
   395→            0.5
   396→        };
   397→
   398→        let block_idx = ((normalized * 7.0).round() as usize).min(7);
   399→        result.push(blocks[block_idx]);
   400→    }
   401→
   402→    result
   403→}
   404→
   405→/// Renders a horizontal bar chart.
   406→pub fn render_bar(
   407→    value: f64,
   408→    max: f64,
   409→    width: usize,
   410→    filled_char: char,
   411→    empty_char: char,
   412→) -> String {
   413→    let pct = if max > 0.0 {
   414→        (value / max).clamp(0.0, 1.0)
   415→    } else {
   416→        0.0
   417→    };
   418→    let filled = (pct * width as f64).round() as usize;
   419→    let empty = width.saturating_sub(filled);
   420→
   421→    format!(
   422→        "{}{}",
   423→        filled_char.to_string().repeat(filled),
   424→        empty_char.to_string().repeat(empty)
   425→    )
   426→}
   427→
   428→/// Format a dollar amount for display.
   429→pub fn format_usd(amount: f64) -> String {
   430→    if amount >= 1000.0 {
   431→        format!("${:.2}K", amount / 1000.0)
   432→    } else if amount >= 100.0 {
   433→        format!("${:.1}", amount)
   434→    } else if amount >= 10.0 {
   435→        format!("${:.2}", amount)
   436→    } else if amount >= 1.0 {
   437→        format!("${:.3}", amount)
   438→    } else {
   439→        format!("${:.4}", amount)
   440→    }
   441→}
   442→
   443→/// Format token count for display.
   444→pub fn format_tokens(tokens: i64) -> String {
   445→    if tokens >= 1_000_000 {
   446→        format!("{:.1}M", tokens as f64 / 1_000_000.0)
   447→    } else if tokens >= 1_000 {
   448→        format!("{:.1}K", tokens as f64 / 1_000.0)
   449→    } else {
   450→        format!("{}", tokens)
   451→    }
   452→}
   453→
   454→/// Truncate model name for display.
   455→pub fn truncate_model_name(model: &str, max_len: usize) -> String {
   456→    // Common abbreviations
   457→    let name = model
   458→        .replace("claude-", "")
   459→        .replace("opus-4-5-20251101", "opus-4.5")
   460→        .replace("opus-4-6", "opus-4.6")
   461→        .replace("sonnet-4-5-20250929", "sonnet-4.5")
   462→        .replace("haiku-4-5-20251001", "haiku-4.5")
   463→        .replace("glm-4.7", "GLM-4.7")
   464→        .replace("deepseek-", "ds-");
   465→
   466→    if name.len() <= max_len {
   467→        name
   468→    } else if max_len > 2 {
   469→        format!("{}…", &name[..max_len - 1])
   470→    } else {
   471→        name[..max_len].to_string()
   472→    }
   473→}
