        // Consume initial scan event
        let _ = watcher.recv_timeout(Duration::from_millis(100));

        // Create workers in different states
        for (id, status) in [
            ("worker-1", "starting"),
            ("worker-2", "active"),
            ("worker-3", "active"),
            ("worker-4", "idle"),
            ("worker-5", "failed"),
        ] {
            let path = status_dir.join(format!("{}.json", id));
            fs::write(
                &path,
                json!({
                    "worker_id": id,
