impl LogWatcher {
    /// Create a new log watcher with default configuration.
    pub fn new(config: LogWatcherConfig) -> Result<(Self, mpsc::Receiver<LogWatcherEvent>), LogWatcherError> {
        // Create the log directory if it doesn't exist
        if !config.log_dir.exists() {
            std::fs::create_dir_all(&config.log_dir).map_err(|e| {
                LogWatcherError::InitError(format!(
                    "Failed to create log directory {:?}: {}",
                    config.log_dir, e
                ))
            })?;
        }

        let (event_tx, event_rx) = mpsc::channel();

        let watcher = Self {
            log_dir: config.log_dir.clone(),
            parser: LogParser::new(),
            tracked_files: HashMap::new(),
            tailer: FileTailer::new(event_tx.clone()),
        };

        // Start file system watcher
        // In tests: use PollWatcher to avoid inotify instance limits
        // In production: use RecommendedWatcher (inotify on Linux) for efficiency
        let log_dir_clone = config.log_dir.clone();
        let event_tx_clone = event_tx.clone();

        #[cfg(test)]
        let mut debouncer = {
            // Use PollWatcher in tests to avoid exhausting inotify limits
            let poll_config = notify::Config::default()
                .with_poll_interval(Duration::from_millis(100));
            new_debouncer_opt(
                config.debounce_duration,
                None,
                move |result: DebounceEventResult| {
                    match result {
                        Ok(events) => {
                            for event in events {
                                if let Err(e) = process_file_event(&event.event, &log_dir_clone, &event_tx_clone) {
                                    let _ = event_tx_clone.send(LogWatcherEvent::Error {
                                        message: e.to_string(),
                                    });
                                }
                            }
                        }
                        Err(errors) => {
                            for error in errors {
                                warn!("File watcher error: {:?}", error);
                            }
                        }
                    }
                },
                poll_config,
            )
            .map_err(|e| LogWatcherError::InitError(format!("Failed to create debouncer: {}", e)))?
        };

        #[cfg(not(test))]
        let mut debouncer = {
            new_debouncer_opt(
                config.debounce_duration,
                None,
                move |result: DebounceEventResult| {
                    match result {
                        Ok(events) => {
                            for event in events {
                                if let Err(e) = process_file_event(&event.event, &log_dir_clone, &event_tx_clone) {
