impl StatusWatcher {
    /// Create a new status watcher with the given configuration.
    pub fn new(config: StatusWatcherConfig) -> StatusWatcherResult<Self> {
        // In test mode, acquire a global mutex to serialize StatusWatcher creation.
        // This prevents exhausting inotify limits when many tests run in parallel.
        #[cfg(test)]
        let _guard = TEST_WATCHER_MUTEX.lock().unwrap();

        // Ensure status directory exists
        if !config.status_dir.exists() {
            if config.create_dir_if_missing {
                std::fs::create_dir_all(&config.status_dir).map_err(|e| {
                    StatusWatcherError::CreateDirectory {
                        path: config.status_dir.clone(),
                        source: e,
                    }
                })?;
                info!(path = ?config.status_dir, "Created status directory");
            } else {
                return Err(StatusWatcherError::DirectoryNotFound(
                    config.status_dir.clone(),
                ));
            }
        }

        // Create channel for status events
        let (event_tx, event_rx) = mpsc::channel();

        // Create debounced watcher
        // In tests: use PollWatcher to avoid inotify instance limits
        // In production: use RecommendedWatcher (inotify on Linux) for efficiency
        let status_dir = config.status_dir.clone();
        let tx_clone = event_tx.clone();

        #[cfg(test)]
        let debouncer = {
            // Use PollWatcher in tests to avoid exhausting inotify limits
            let poll_config = notify::Config::default()
                .with_poll_interval(Duration::from_millis(100));
            new_debouncer_opt::<_, PollWatcher, _>(
                Duration::from_millis(config.debounce_ms),
                None,
                move |result: DebounceEventResult| {
                    Self::handle_debounced_events(result, &status_dir, &tx_clone);
                },
                NoCache,
                poll_config,
            )?
        };

        #[cfg(not(test))]
        let debouncer = {
            new_debouncer_opt::<_, RecommendedWatcher, _>(
                Duration::from_millis(config.debounce_ms),
                None,
                move |result: DebounceEventResult| {
                    Self::handle_debounced_events(result, &status_dir, &tx_clone);
                },
                RecommendedCache::new(),
                notify::Config::default(),
            )?
        };

        let mut watcher = Self {
            config,
            _debouncer: Some(debouncer),
            event_rx,
            workers: HashMap::new(),
        };

        // Start watching the directory
        watcher.start_watching()?;

        // Perform initial scan
        watcher.initial_scan(event_tx)?;

        Ok(watcher)
    }

    /// Create a new status watcher with default configuration.
    pub fn new_default() -> StatusWatcherResult<Self> {
        Self::new(StatusWatcherConfig::default())
    }

    /// Stop watching and release resources.
    ///
    /// This method should be called when the watcher is no longer needed
    /// to ensure the inotify instance is released immediately.
    pub fn stop(&mut self) {
        // The debouncer's stop method takes ownership, so we need to take it
        if let Some(debouncer) = self._debouncer.take() {
            debouncer.stop();
            debug!("Status watcher stopped");
        }
    }

    /// Start watching the status directory.
    fn start_watching(&mut self) -> StatusWatcherResult<()> {
        if let Some(ref mut debouncer) = self._debouncer {
            debouncer.watch(&self.config.status_dir, RecursiveMode::NonRecursive)?;

